def score(result, args):
    n = args[0]
    best = {3: 9, 4: 20, 5: 45}[n]
    vecs = [tuple(v) for v in result]
    if len(set(vecs)) != len(vecs):
        return 0.0
    if any(len(v) != n or any(c not in (0, 1, 2) for c in v) for v in vecs):
        return 0.0
    s = set(vecs)
    for i, x in enumerate(vecs):
        for y in vecs[i+1:]:
            z = tuple((-a - b) % 3 for a, b in zip(x, y))
            if z in s and z != x and z != y:
                return 0.0
    return len(vecs) / best
